const typeData = $('🔍 تحديد نوع الرابط').first().json;
const jinaData = $('🌐 جلب المحتوى (Jina Premium)').first().json;
const aiData = $input.first().json;

const content = jinaData.body || jinaData.data || '';
const summary = aiData.response || '';
const wordCount = content.split(/\s+/).length;

const markdown = `---
title: "${typeData.title || typeData.url}"
url: ${typeData.url}
type: ${typeData.type}
date: ${typeData.timestamp}
words: ${wordCount}
source_file: ${typeData.fileName}
---

# ${typeData.title || 'محتوى من: ' + typeData.url}

**المصدر:** ${typeData.url}  
**النوع:** ${typeData.type}  
**التاريخ:** ${new Date(typeData.timestamp).toLocaleDateString('ar-SA')}  
**الملف الأصلي:** ${typeData.fileName}

---

## 📋 الملخص الذكي

${summary}

---

## 📄 المحتوى الكامل

${content}
`;

return [{ json: {
  ...typeData,
  markdown,
  wordCount
}}];

// حفظ ملف Markdown في knowledge_inbox ونقل الملف الأصلي إلى url_processed
const fs = require('fs');
const path = require('path');

const { markdown, outputFilename, filePath, fileName } = $input.first().json;

const knowledgeInboxDir = 'D:\\SaleHSaaS3\\knowledge_inbox';
const urlProcessedDir = 'D:\\SaleHSaaS3\\url_processed';

// إنشاء المجلدات إذا لم تكن موجودة
if (!fs.existsSync(knowledgeInboxDir)) {
  fs.mkdirSync(knowledgeInboxDir, { recursive: true });
}
if (!fs.existsSync(urlProcessedDir)) {
  fs.mkdirSync(urlProcessedDir, { recursive: true });
}

// حفظ ملف Markdown
const outputPath = path.join(knowledgeInboxDir, outputFilename);
fs.writeFileSync(outputPath, markdown, 'utf8');

// نقل الملف الأصلي إلى url_processed
const destPath = path.join(urlProcessedDir, fileName);
try {
  fs.renameSync(filePath, destPath);
} catch (e) {
  // إذا فشل rename (مثلاً بسبب اختلاف القرص) استخدم copy+delete
  fs.copyFileSync(filePath, destPath);
  fs.unlinkSync(filePath);
}

return [{ json: {
  ...($input.first().json),
  savedTo: outputPath,
  movedFrom: filePath,
  movedTo: destPath,
  success: true
}}];

// تسجيل في السجل
const data = $input.first().json;
console.log(`✅ تمت معالجة: ${data.fileName} → ${data.outputFilename} (${data.wordCount} كلمة)`);
return [{ json: {
  success: true,
  sourceFile: data.fileName,
  outputFile: data.outputFilename,
  savedTo: data.savedTo,
  movedTo: data.movedTo,
  url: data.url,
  type: data.type,
  words: data.wordCount,
  timestamp: new Date().toISOString()
}}];
